// Generate compact interpretations for remaining planets using themes
["Mars", "Mercury", "Jupiter", "Venus", "Saturn", "Rahu", "Ketu"].forEach(planet => {
    PLANET_IN_NAKSHATRA[planet] = {};
    Object.entries(NAKSHATRA_THEMES).forEach(([nakshatra, theme]) => {
        const planetKeywords: Record<string, string> = {
            Mars: "courage, passion, and decisive action", Mercury: "intellect, communication, and analytical skill",
            Jupiter: "wisdom, grace, and dharmic expansion", Venus: "beauty, love, and artistic refinement",
            Saturn: "discipline, patience, and karmic responsibility", Rahu: "ambition, innovation, and unconventional drive",
            Ketu: "spiritual liberation, past-life mastery, and intuitive depth",
        };
        PLANET_IN_NAKSHATRA[planet][nakshatra] =
            `${planet} in ${nakshatra}: ${planet}'s energy of ${planetKeywords[planet]} is channeled through the Nakshatra themes of ${theme}. This creates a person who expresses ${planet}'s qualities through ${nakshatra}'s specific field of life — bringing a unique, potent signature to your horoscope that directly shapes how you act, communicate, relate, grow, and evolve in this dimension of life.`;
    });
});
